# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql

def lambda_handler(event, context):
    # Get the parameters from the event
    search_params = event['queryStringParameters']

    # Connect to the database
    conn = pymysql.connect(host='your_host',
                           user='your_user',
                           password='your_password',
                           db='your_db',
                           charset='utf8mb4',
                           cursorclass=pymysql.cursors.DictCursor)

    try:
        with conn.cursor() as cursor:
            # Build the SQL query
            sql = "SELECT * FROM products WHERE "
            sql += " AND ".join(f"{key} = %s" for key in search_params.keys())

            # Execute the SQL query
            cursor.execute(sql, tuple(search_params.values()))

            # Fetch the results
            result = cursor.fetchall()

    finally:
        conn.close()

    # Return the results
    return {
        'statusCode': 200,
        'body': json.dumps(result)
    }